// Producer method
async IAsyncEnumerable<CsvRow> ReadCsvAsync(
    string path,
    [EnumeratorCancellation] CancellationToken ct = default)
{
    using var reader = new StreamReader(path);
    string? line;
    while ((line = await reader.ReadLineAsync(ct)) is not null)
        yield return ParseRow(line);
}

// Chunk để batch
await foreach (var chunk in ReadCsvAsync(path,ct).Chunk(500))
    await db.BulkInsertAsync(chunk, ct);
